BEGIN;



WITH payload AS (
  SELECT $RISQQ151${"questions":[{"section_code":"17A","section_number":17,"section_letter":"A","section_title":"Ship To Ship Operation","printed_question_no":"17.6","internal_question_no":"17A.006","question_sort_key":17100600.558,"question_text":"Was the vessel equipped with STS specific contingency plans to address all potential emergencies during the STS operation and, were the Master and deck officers familiar with the contents of these plans and the various contingency scenarios?","guide_to_inspection":"The contingency plan should outline the control measures, responsibilities, and actions required on both ships. The plan should\nbe relevant to the location of the operation, taking into account the resources available both at the transfer area and in terms of\nnearby backup support. It should also cover the requirement for drills in various emergency scenarios.\nEmergency scenarios should cover the full scope of the operation. Examples of such scenarios are as follows:\n> Vessel collision during mooring/unmooring maneuvers,\n> Cargo pollution at sea,\n> Fire/explosion,\n> Multiple mooring line failure,\n> Emergency unmooring,\n> Emergency on own vessel or other vessel involved in operation,","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":231,"source_page_end":231,"raw_source_text":"Was the vessel equipped with STS specific contingency plans to address all potential emergencies during\nthe STS operation and, were the Master and deck officers familiar with the contents of these plans and\nthe various contingency scenarios?(V)\nGuide to Inspection\nThe contingency plan should outline the control measures, responsibilities, and actions required on both ships. The plan should\nbe relevant to the location of the operation, taking into account the resources available both at the transfer area and in terms of\nnearby backup support. It should also cover the requirement for drills in various emergency scenarios.\nEmergency scenarios should cover the full scope of the operation. Examples of such scenarios are as follows:\n> Vessel collision during mooring/unmooring maneuvers,\n> Cargo pollution at sea,\n> Fire/explosion,\n> Multiple mooring line failure,\n> Emergency unmooring,\n> Emergency on own vessel or other vessel involved in operation,","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"17A","section_number":17,"section_letter":"A","section_title":"Ship To Ship Operation","printed_question_no":"17.7","internal_question_no":"17A.007","question_sort_key":17100700.559,"question_text":"Has the company identified additional roles and responsibilities that necessitate training and familiarisation for the Officers to conduct the STS operation safely and effectively? Have the Master and Officers undergone suitable training for these roles?","guide_to_inspection":"The crew may need to take on additional or different tasks, roles, and responsibilities compared to those required during routine\nport and cargo operations. It’s crucial that any additional roles and responsibilities are identified, and that appropriate training is\nprovided before the operation. The training requirements for each ship will vary based on the recent experience of the individuals\non board. Factors such as location, services provided, and equipment may necessitate additional training for experienced\npersonnel. If there is little or no experience with Ship-to-Ship (STS) operations, consideration should be given to bringing in\nadditional experienced STS personnel prior to the operation. This can assist with the training of personnel and the execution of\nthe STS operation.\nTraining may include items such as:\n> Roles and responsibilities of involved parties.\n> Bridge watchkeeping procedures.\n> Deck watchkeeping procedures.\n> Machinery operation.\n> Mooring and unmooring, which includes procedures for passing lines between vessels, properties of mooring lines, fender\nmanagement, measures to minimise chafing of lines, and awareness of snap-back zones.\n> Operation of cranes /conveyors.\n> Personnel transfer.\n> Transfer equipment.\n> Emergency operations, such as aborting mooring operations, collision, cargo spill, and emergency departure.\nThe level of knowledge and training required will depend on a person’s role and past experience.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":232,"source_page_end":232,"raw_source_text":"Has the company identified additional roles and responsibilities that necessitate training and\nfamiliarisation for the Officers to conduct the STS operation safely and effectively? Have the Master\nand Officers undergone suitable training for these roles?(V)\nGuide to Inspection\nThe crew may need to take on additional or different tasks, roles, and responsibilities compared to those required during routine\nport and cargo operations. It’s crucial that any additional roles and responsibilities are identified, and that appropriate training is\nprovided before the operation. The training requirements for each ship will vary based on the recent experience of the individuals\non board. Factors such as location, services provided, and equipment may necessitate additional training for experienced\npersonnel. If there is little or no experience with Ship-to-Ship (STS) operations, consideration should be given to bringing in\nadditional experienced STS personnel prior to the operation. This can assist with the training of personnel and the execution of\nthe STS operation.\nTraining may include items such as:\n> Roles and responsibilities of involved parties.\n> Bridge watchkeeping procedures.\n> Deck watchkeeping procedures.\n> Machinery operation.\n> Mooring and unmooring, which includes procedures for passing lines between vessels, properties of mooring lines, fender\nmanagement, measures to minimise chafing of lines, and awareness of snap-back zones.\n> Operation of cranes /conveyors.\n> Personnel transfer.\n> Transfer equipment.\n> Emergency operations, such as aborting mooring operations, collision, cargo spill, and emergency departure.\nThe level of knowledge and training required will depend on a person’s role and past experience.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"17A","section_number":17,"section_letter":"A","section_title":"Ship To Ship Operation","printed_question_no":"17.8","internal_question_no":"17A.008","question_sort_key":17100800.56,"question_text":"Has the vessel’s manager developed procedures that require post-operation feedback and assessment by the Master and, where applicable, was there objective evidence demonstrating that such feedback was provided after the last STS operation?","guide_to_inspection":"The vessel’s manager should develop a procedure that details the content of the post-operation feedback and assessment by\nthe master. This may include, but is not limited to, the following:\n> Environmental Conditions (e.g., weather, sea state),\n> Vessel Handling and Maneuvering,\n> Performance/ suitability of the STS Location,\n> Performance of participating vessel,\n> Performance of the STS Organizer/ STS Superintendent,\n> Communication Effectiveness,\n> Equipment Performance and Reliability,\n> Safety Procedures and Emergency Response,\n> Crew Competency and Training,\n> Compliance with Regulations and Guidelines,\n> Incident Reporting and Lessons Learned.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":232,"source_page_end":232,"raw_source_text":"Has the vessel’s manager developed procedures that require post-operation feedback and assessment\nby the Master and, where applicable, was there objective evidence demonstrating that such feedback\nwas provided after the last STS operation?(V)\nGuide to Inspection\nThe vessel’s manager should develop a procedure that details the content of the post-operation feedback and assessment by\nthe master. This may include, but is not limited to, the following:\n> Environmental Conditions (e.g., weather, sea state),\n> Vessel Handling and Maneuvering,\n> Performance/ suitability of the STS Location,\n> Performance of participating vessel,\n> Performance of the STS Organizer/ STS Superintendent,\n> Communication Effectiveness,\n> Equipment Performance and Reliability,\n> Safety Procedures and Emergency Response,\n> Crew Competency and Training,\n> Compliance with Regulations and Guidelines,\n> Incident Reporting and Lessons Learned.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"17A","section_number":17,"section_letter":"A","section_title":"Ship To Ship Operation","printed_question_no":"17.9","internal_question_no":"17A.009","question_sort_key":17100900.561,"question_text":"Was the vessel provided with STS operational and safety checklists, and was there documented evidence that demonstrated the effective use of the checklist?","guide_to_inspection":"Checklists are crucial risk management tools designed to ensure that operations are conducted safely. They serve as essential\nreminders of the principal safety factors to be considered, but they should be supplemented by continuous vigilance throughout\nthe entire operation. Checklists should be developed to specifically address factors that are relevant to the STS operation.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":232,"source_page_end":232,"raw_source_text":"Was the vessel provided with STS operational and safety checklists, and was there documented evidence\nthat demonstrated the effective use of the checklist?(V)\nGuide to Inspection\nChecklists are crucial risk management tools designed to ensure that operations are conducted safely. They serve as essential\nreminders of the principal safety factors to be considered, but they should be supplemented by continuous vigilance throughout\nthe entire operation. Checklists should be developed to specifically address factors that are relevant to the STS operation.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"17A","section_number":17,"section_letter":"A","section_title":"Ship To Ship Operation","printed_question_no":"17.10","internal_question_no":"17A.010","question_sort_key":17101000.562,"question_text":"Was the STS equipment, including fenders, cargo transfer systems, mooring equipment, personnel transfers, and ancillary equipment, in good condition, and was there documented evidence indicating that the STS equipment was maintained and checked prior to the STS operation?","guide_to_inspection":"Floating Pneumatic Rubber Fenders:\nBulk carrier(s) should be equipped with primary fenders. These fenders must be capable of withstanding anticipated berthing\nenergies and evenly distributing the forces over the appropriate areas of both bulk carriers’ hulls. It is recommended to use\nfenders that are constructed and maintained according to ISO 17357. In line with industry best practices, the safety valve on\npneumatic fenders should be inspected at intervals not exceeding two years, and a certificate should be provided as evidence\nof this inspection. The fenders, and their pennants should be maintained in good condition. Objective evidence of a visual\ninspection prior to the STS operation should be available on board.\nUse of gravity-based self-unloading and/or hybrid self-unloading system:\nThe components of the gravity-based self-unloading system or hybrid self-unloading system (including conveyor belts and\ncranes) used for the STS transfer of bulk cargos should be maintained and kept in good working condition, as per manufacturer\nor industry recommendations.\nMooring Equipment:\nIt is important that ships involved in STS operations are equipped with good quality mooring lines, efficient winches, well-placed\nand sufficiently strong fairleads, bollards, and other associated mooring equipment. All mooring equipment should be in good\norder and free of defects.\nPersonnel transfer-at Sea operation:\nA plan for personnel transfer should be prepared in advance and incorporated into the SMS. This plan should encompass a\ndetailed risk assessment of the entire operation and receive approval from the masters of both ships involved. It should be\ncommunicated to all personnel involved. The plan should identify all potential risks and include pre-testing of equipment,\nestablish clear communication lines, and devise a contingency plan for emergencies.\nThe frequency of personnel transfers between ships should be minimised as much as possible. The safest method of transfer\nshould be determined through a risk assessment, taking into account the prevailing conditions and circumstances at the time\nand location of the proposed transfer. The risks associated with such transfers should be compared with the risks associated\nwith other available transfer methods.\nPotential means of transfer could include the accommodation ladder, a workboat, or a personnel transfer basket. If a cargo\nor provision crane is used, it must be upgraded prior to transferring personnel and certified for personnel transfer by the\nclassification society.\nThe Personal Transfer Basket (PTB) should be approved and certified specifically for the transportation of personnel. The PTB\nshould not be repurposed for other uses on board, such as serving as work platforms.\nAncillary Equipment:\nAncillary equipment refers to the additional apparatus used in conjunction with the main equipment to form a complete system.\nFor the STS operation, the ancillary equipment, which includes wires, messengers, stoppers, strops, and shackles, should be\ninspected for their condition before initiating the STS operation.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":233,"source_page_end":233,"raw_source_text":"Was the STS equipment, including fenders, cargo transfer systems, mooring equipment, personnel transfers,\nand ancillary equipment, in good condition, and was there documented evidence indicating that the STS\nequipment was maintained and checked prior to the STS operation?(V)\nGuide to Inspection\nFloating Pneumatic Rubber Fenders:\nBulk carrier(s) should be equipped with primary fenders. These fenders must be capable of withstanding anticipated berthing\nenergies and evenly distributing the forces over the appropriate areas of both bulk carriers’ hulls. It is recommended to use\nfenders that are constructed and maintained according to ISO 17357. In line with industry best practices, the safety valve on\npneumatic fenders should be inspected at intervals not exceeding two years, and a certificate should be provided as evidence\nof this inspection. The fenders, and their pennants should be maintained in good condition. Objective evidence of a visual\ninspection prior to the STS operation should be available on board.\nUse of gravity-based self-unloading and/or hybrid self-unloading system:\nThe components of the gravity-based self-unloading system or hybrid self-unloading system (including conveyor belts and\ncranes) used for the STS transfer of bulk cargos should be maintained and kept in good working condition, as per manufacturer\nor industry recommendations.\nMooring Equipment:\nIt is important that ships involved in STS operations are equipped with good quality mooring lines, efficient winches, well-placed\nand sufficiently strong fairleads, bollards, and other associated mooring equipment. All mooring equipment should be in good\norder and free of defects.\nPersonnel transfer-at Sea operation:\nA plan for personnel transfer should be prepared in advance and incorporated into the SMS. This plan should encompass a\ndetailed risk assessment of the entire operation and receive approval from the masters of both ships involved. It should be\ncommunicated to all personnel involved. The plan should identify all potential risks and include pre-testing of equipment,\nestablish clear communication lines, and devise a contingency plan for emergencies.\nThe frequency of personnel transfers between ships should be minimised as much as possible. The safest method of transfer\nshould be determined through a risk assessment, taking into account the prevailing conditions and circumstances at the time\nand location of the proposed transfer. The risks associated with such transfers should be compared with the risks associated\nwith other available transfer methods.\nPotential means of transfer could include the accommodation ladder, a workboat, or a personnel transfer basket. If a cargo\nor provision crane is used, it must be upgraded prior to transferring personnel and certified for personnel transfer by the\nclassification society.\nThe Personal Transfer Basket (PTB) should be approved and certified specifically for the transportation of personnel. The PTB\nshould not be repurposed for other uses on board, such as serving as work platforms.\nAncillary Equipment:\nAncillary equipment refers to the additional apparatus used in conjunction with the main equipment to form a complete system.\nFor the STS operation, the ancillary equipment, which includes wires, messengers, stoppers, strops, and shackles, should be\ninspected for their condition before initiating the STS operation.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"17A","section_number":17,"section_letter":"A","section_title":"Ship To Ship Operation","printed_question_no":"17.11","internal_question_no":"17A.011","question_sort_key":17101100.563,"question_text":"Has the STS Unit Questionnaire been completed by either the STS Organiser or the STS Unit Manager, and is there available objective evidence from the managers, demonstrating that any identified gaps in the questionnaire have been assessed and addressed through appropriate risk mitigation measures to ensure the safety of the Ocean-Going Vessel during operations with the unit(s)?","guide_to_inspection":"Definitions and Purpose of the STS Unit Questionnaire\nThe term “unit” refers to any floating structure involved in transshipment operations, including barges, floating cranes, and\noffshore support vessels. While these may not be classified as traditional vessels, they are essential to the transshipment\nprocess .\nSTS Organiser: A shore-based company responsible for coordinating and managing STS transfer operations. The STS Organiser\nmay also serve as an STS Service Provider.\nSTS Unit Manager: A company or individual responsible for the technical and operational management of a transshipment unit\nsuch as a transloader, floating crane, or barge engaged in STS transfer operations.\nThis questionnaire is intended to be completed prior to transshipment operations involving the transfer of dry cargo between\nthe unit and an oceangoing vessel. Its primary objective is to assess the condition and operational standards of each unit\nparticipating in the operation.\nResponsibilities and Requirements\nThe questionnaire should be submitted by the vessel’s manager through established commercial channels typically via the\nCharterer or Cargo Owner, requesting its completion for each transshipment unit involved in the STS operation.\nGiven that there may be no direct contractual relationship between the vessel’s manager and the STS Unit Manager, all\ncommunications should be routed through the party holding the commercial agreement with the STS Unit. This practice is\nconsistent with standard procedures across other sectors of the maritime industry and helps ensure clarity, accountability, and\nproper coordination.\nOnce completed, the questionnaire remains valid for a period of 12 months. If multiple operations are conducted with the same\nSTS Unit within that timeframe, it is not necessary to complete a new questionnaire for each operation.\nThe information gathered is used to:\n> Assess the level of compliance of all parties involved\n> Evaluate the operational standards of participating units\n> Identify the necessary risk mitigation measures, taking into account all parameters that may impact the safety and\nefficiency of the STS operation.\n> Improve onboard STS practices on the mother vessel.\nDocumentation and Inspection Protocol\nFor any STS operation involving non-ocean-going vessels, inspectors must upload the completed questionnaire to Q 17.11.\nA copy of the completed form should be readily available onboard and included in the final inspection documentation.\nExceptional Circumstances\nIn cases where, despite the vessel manager’s due diligence, the questionnaire cannot be completed in time, the vessel manager\nshould:\n> Conduct and document a risk assessment addressing the absence of the STS Unit Questionnaire\n> Notify relevant stakeholders as required\nClick here to access a sample of the questionnaire for reference and review.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":234,"source_page_end":234,"raw_source_text":"Has the STS Unit Questionnaire been completed by either the STS Organiser or the STS Unit Manager, and is\nthere available objective evidence from the managers, demonstrating that any identified gaps in the questionnaire\nhave been assessed and addressed through appropriate risk mitigation measures to ensure the safety of the\nOcean-Going Vessel during operations with the unit(s)? (V)\nGuide to Inspection\nDefinitions and Purpose of the STS Unit Questionnaire\nThe term “unit” refers to any floating structure involved in transshipment operations, including barges, floating cranes, and\noffshore support vessels. While these may not be classified as traditional vessels, they are essential to the transshipment\nprocess .\nSTS Organiser: A shore-based company responsible for coordinating and managing STS transfer operations. The STS Organiser\nmay also serve as an STS Service Provider.\nSTS Unit Manager: A company or individual responsible for the technical and operational management of a transshipment unit\nsuch as a transloader, floating crane, or barge engaged in STS transfer operations.\nThis questionnaire is intended to be completed prior to transshipment operations involving the transfer of dry cargo between\nthe unit and an oceangoing vessel. Its primary objective is to assess the condition and operational standards of each unit\nparticipating in the operation.\nResponsibilities and Requirements\nThe questionnaire should be submitted by the vessel’s manager through established commercial channels typically via the\nCharterer or Cargo Owner, requesting its completion for each transshipment unit involved in the STS operation.\nGiven that there may be no direct contractual relationship between the vessel’s manager and the STS Unit Manager, all\ncommunications should be routed through the party holding the commercial agreement with the STS Unit. This practice is\nconsistent with standard procedures across other sectors of the maritime industry and helps ensure clarity, accountability, and\nproper coordination.\nOnce completed, the questionnaire remains valid for a period of 12 months. If multiple operations are conducted with the same\nSTS Unit within that timeframe, it is not necessary to complete a new questionnaire for each operation.\nThe information gathered is used to:\n> Assess the level of compliance of all parties involved\n> Evaluate the operational standards of participating units\n> Identify the necessary risk mitigation measures, taking into account all parameters that may impact the safety and\nefficiency of the STS operation.\n> Improve onboard STS practices on the mother vessel.\nDocumentation and Inspection Protocol\nFor any STS operation involving non-ocean-going vessels, inspectors must upload the completed questionnaire to Q 17.11.\nA copy of the completed form should be readily available onboard and included in the final inspection documentation.\nExceptional Circumstances\nIn cases where, despite the vessel manager’s due diligence, the questionnaire cannot be completed in time, the vessel manager\nshould:\n> Conduct and document a risk assessment addressing the absence of the STS Unit Questionnaire\n> Notify relevant stakeholders as required\nClick here to access a sample of the questionnaire for reference and review.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ151$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 15/15 imported.' AS result,
  '17A.006' AS chunk_first_question,
  '17A.011' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
